import SwiftUI
import AIUsagesTrackersLib

struct SegmentEditor: View {
    let preferences: any AppPreferences
    @Bindable var store: UsageStore
    let index: Int

    private var segmentBinding: Binding<MenuBarSegmentConfig>? {
        guard preferences.menuBarSegments.indices.contains(index) else { return nil }
        return Binding(
            get: { preferences.menuBarSegments[index] },
            set: { preferences.menuBarSegments[index] = $0 }
        )
    }

    var body: some View {
        if let segmentBinding {
            VStack(alignment: .leading, spacing: 12) {
                vendorPicker(segmentBinding)
                accountPicker(segmentBinding)
                metricPicker(segmentBinding)

                Divider()

                switch segmentBinding.wrappedValue.display {
                case .timeWindow:
                    timeWindowEditor(segmentBinding)
                case .payAsYouGo:
                    payAsYouGoInfo(segmentBinding)
                }
            }
        }
    }

    // MARK: Vendor

    private func vendorPicker(_ binding: Binding<MenuBarSegmentConfig>) -> some View {
        let vendors = availableVendors
        return HStack {
            Text("Vendor")
                .frame(width: 80, alignment: .leading)
            Picker("", selection: Binding(
                get: { binding.wrappedValue.vendor },
                set: { newVendor in
                    var seg = binding.wrappedValue
                    seg.vendor = newVendor
                    // Reset account + metric to first valid couple for the new vendor
                    seg.account = .currentlyActive
                    seg.metricName = firstMetricName(vendor: newVendor, account: seg.account) ?? ""
                    seg.display = defaultDisplay(
                        vendor: newVendor,
                        account: seg.account,
                        metricName: seg.metricName
                    )
                    binding.wrappedValue = seg
                }
            )) {
                ForEach(vendors, id: \.rawValue) { vendor in
                    VendorLabelView(vendor: vendor).tag(vendor)
                }
            }
            .labelsHidden()
            .pickerStyle(.menu)
        }
    }

    // MARK: Account

    private func accountPicker(_ binding: Binding<MenuBarSegmentConfig>) -> some View {
        let accounts = availableAccounts(for: binding.wrappedValue.vendor)
        return HStack {
            Text("Account")
                .frame(width: 80, alignment: .leading)
            Picker("", selection: Binding(
                get: { binding.wrappedValue.account },
                set: { newAccount in
                    var seg = binding.wrappedValue
                    seg.account = newAccount
                    if firstMetricName(vendor: seg.vendor, account: newAccount) == nil {
                        // No metrics on new account — keep metric name so the warning shows
                    } else if !metricExists(on: seg.vendor, account: newAccount, name: seg.metricName) {
                        seg.metricName = firstMetricName(vendor: seg.vendor, account: newAccount) ?? ""
                        seg.display = defaultDisplay(
                            vendor: seg.vendor,
                            account: newAccount,
                            metricName: seg.metricName
                        )
                    }
                    binding.wrappedValue = seg
                }
            )) {
                Text("Currently active account").tag(AccountSelection.currentlyActive)
                Divider()
                ForEach(accounts, id: \.rawValue) { email in
                    Text(email.rawValue).tag(AccountSelection.specific(email))
                }
            }
            .labelsHidden()
        }
    }

    // MARK: Metric

    private func metricPicker(_ binding: Binding<MenuBarSegmentConfig>) -> some View {
        let metrics = availableMetrics(
            vendor: binding.wrappedValue.vendor,
            account: binding.wrappedValue.account
        )
        return HStack {
            Text("Metric")
                .frame(width: 80, alignment: .leading)
            if metrics.isEmpty {
                Text("No metrics available")
                    .foregroundStyle(.secondary)
                    .font(.caption)
            } else {
                Picker("", selection: Binding(
                    get: { binding.wrappedValue.metricName },
                    set: { newName in
                        var seg = binding.wrappedValue
                        seg.metricName = newName
                        seg.display = defaultDisplay(
                            vendor: seg.vendor,
                            account: seg.account,
                            metricName: newName
                        )
                        binding.wrappedValue = seg
                    }
                )) {
                    ForEach(metrics, id: \.name) { option in
                        Text(option.name).tag(option.name)
                    }
                }
                .labelsHidden()
            }
        }
    }

    // MARK: Time-window editor

    private func timeWindowEditor(_ binding: Binding<MenuBarSegmentConfig>) -> some View {
        let displayBinding = Binding<TimeWindowDisplay>(
            get: {
                if case .timeWindow(let d) = binding.wrappedValue.display {
                    return d
                }
                return TimeWindowDisplay()
            },
            set: { newDisplay in
                var seg = binding.wrappedValue
                seg.display = .timeWindow(newDisplay)
                binding.wrappedValue = seg
            }
        )

        return VStack(alignment: .leading, spacing: 8) {
            Text("Display")
                .font(.caption)
                .foregroundStyle(.secondary)
                .textCase(.uppercase)

            Toggle("Colored status dot", isOn: displayBinding.showDot)
            HStack {
                Toggle("Metric short label", isOn: displayBinding.showLetter)
                    .fixedSize()
                TextField("", text: displayBinding.letter)
                    .textFieldStyle(.roundedBorder)
                    .frame(width: 48)
            }
            Toggle("Usage percentage", isOn: displayBinding.showPercent)
            Toggle("Time until reset", isOn: displayBinding.showReset)
        }
    }

    // MARK: Pay-as-you-go info

    private func payAsYouGoInfo(_ binding: Binding<MenuBarSegmentConfig>) -> some View {
        let preview = previewPayAsYouGo(for: binding.wrappedValue) ?? "—"
        return HStack(spacing: 6) {
            Image(systemName: "info.circle")
                .foregroundStyle(.secondary)
            Text("This metric displays \"\(preview)\" — no additional options.")
                .font(.caption)
                .foregroundStyle(.secondary)
        }
    }

    // MARK: Data helpers

    private var availableVendors: [Vendor] {
        Array(Set(store.entries.map(\.vendor))).sorted { $0.rawValue < $1.rawValue }
    }

    private func availableAccounts(for vendor: Vendor) -> [AccountEmail] {
        store.entries
            .filter { $0.vendor == vendor && !$0.metrics.isEmpty }
            .map(\.account)
    }

    private struct MetricOption: Hashable {
        let name: String
        let kind: MetricKind
    }

    private func availableMetrics(
        vendor: Vendor,
        account: AccountSelection
    ) -> [MetricOption] {
        guard let entry = resolveEntry(vendor: vendor, account: account) else { return [] }
        return entry.metrics.compactMap { metric in
            guard let name = SegmentEditingHelpers.metricName(metric) else { return nil }
            return MetricOption(name: name, kind: metric.kind)
        }
    }

    private func resolveEntry(vendor: Vendor, account: AccountSelection) -> VendorUsageEntry? {
        let vendorEntries = store.entries.filter { $0.vendor == vendor }
        switch account {
        case .currentlyActive:
            return vendorEntries.first(where: { $0.isActive })
        case .specific(let email):
            return vendorEntries.first(where: { $0.account == email })
        }
    }

    private func firstMetricName(vendor: Vendor, account: AccountSelection) -> String? {
        resolveEntry(vendor: vendor, account: account)?
            .metrics
            .compactMap(SegmentEditingHelpers.metricName)
            .first
    }

    private func metricExists(on vendor: Vendor, account: AccountSelection, name: String) -> Bool {
        guard let entry = resolveEntry(vendor: vendor, account: account) else { return false }
        return entry.metrics.contains { SegmentEditingHelpers.metricName($0) == name }
    }

    private func defaultDisplay(
        vendor: Vendor,
        account: AccountSelection,
        metricName: String
    ) -> SegmentDisplay {
        guard let entry = resolveEntry(vendor: vendor, account: account),
              let metric = entry.metrics.first(where: { SegmentEditingHelpers.metricName($0) == metricName }) else {
            return .timeWindow(TimeWindowDisplay(letter: MenuBarMetricLetter.defaultLetter(for: metricName)))
        }
        switch metric {
        case .payAsYouGo:
            return .payAsYouGo
        case .timeWindow, .unknown:
            return .timeWindow(TimeWindowDisplay(letter: MenuBarMetricLetter.defaultLetter(for: metricName)))
        }
    }

    private func previewPayAsYouGo(for segment: MenuBarSegmentConfig) -> String? {
        guard let entry = resolveEntry(vendor: segment.vendor, account: segment.account),
              let metric = entry.metrics.first(where: { SegmentEditingHelpers.metricName($0) == segment.metricName }),
              case let .payAsYouGo(_, amount, currency) = metric else {
            return nil
        }
        return String(format: "%.2f %@", amount, currency)
    }
}

import Foundation

// MARK: - AccountSelection

/// Which account a segment targets. `.currentlyActive` re-resolves at render time
/// so the segment tracks whichever Claude account is currently active.
public enum AccountSelection: Codable, Equatable, Hashable, Sendable {
    case currentlyActive
    case specific(AccountEmail)

    private enum CodingKeys: String, CodingKey {
        case kind, email
    }

    private enum Kind: String, Codable {
        case currentlyActive = "currently-active"
        case specific
    }

    public init(from decoder: Decoder) throws {
        let container = try decoder.container(keyedBy: CodingKeys.self)
        let kind = try container.decode(Kind.self, forKey: .kind)
        switch kind {
        case .currentlyActive:
            self = .currentlyActive
        case .specific:
            let email = try container.decode(AccountEmail.self, forKey: .email)
            self = .specific(email)
        }
    }

    public func encode(to encoder: Encoder) throws {
        var container = encoder.container(keyedBy: CodingKeys.self)
        switch self {
        case .currentlyActive:
            try container.encode(Kind.currentlyActive, forKey: .kind)
        case .specific(let email):
            try container.encode(Kind.specific, forKey: .kind)
            try container.encode(email, forKey: .email)
        }
    }
}

// MARK: - SegmentDisplay

/// Variant-dependent display options. `timeWindow` carries four independent
/// toggles plus the letter shown when `showLetter` is on; `payAsYouGo` has no
/// options — the rendered text is always "amount currency".
public enum SegmentDisplay: Codable, Equatable, Hashable, Sendable {
    case timeWindow(TimeWindowDisplay)
    case payAsYouGo

    private enum CodingKeys: String, CodingKey {
        case kind, timeWindow
    }

    private enum Kind: String, Codable {
        case timeWindow = "time-window"
        case payAsYouGo = "pay-as-you-go"
    }

    public init(from decoder: Decoder) throws {
        let container = try decoder.container(keyedBy: CodingKeys.self)
        let kind = try container.decode(Kind.self, forKey: .kind)
        switch kind {
        case .timeWindow:
            let tw = try container.decode(TimeWindowDisplay.self, forKey: .timeWindow)
            self = .timeWindow(tw)
        case .payAsYouGo:
            self = .payAsYouGo
        }
    }

    public func encode(to encoder: Encoder) throws {
        var container = encoder.container(keyedBy: CodingKeys.self)
        switch self {
        case .timeWindow(let tw):
            try container.encode(Kind.timeWindow, forKey: .kind)
            try container.encode(tw, forKey: .timeWindow)
        case .payAsYouGo:
            try container.encode(Kind.payAsYouGo, forKey: .kind)
        }
    }
}

public struct TimeWindowDisplay: Codable, Equatable, Hashable, Sendable {
    public var showDot: Bool
    public var showLetter: Bool
    public var letter: String
    public var showPercent: Bool
    public var showReset: Bool

    public init(
        showDot: Bool = true,
        showLetter: Bool = true,
        letter: String = "",
        showPercent: Bool = true,
        showReset: Bool = true
    ) {
        self.showDot = showDot
        self.showLetter = showLetter
        self.letter = letter
        self.showPercent = showPercent
        self.showReset = showReset
    }
}

// MARK: - MenuBarSegmentConfig

/// A user-configured menu bar segment: which metric to read (vendor/account/metric)
/// and how to display it. Persisted as JSON in UserDefaults.
public struct MenuBarSegmentConfig: Codable, Equatable, Hashable, Sendable, Identifiable {
    public let id: UUID
    public var vendor: Vendor
    public var account: AccountSelection
    public var metricName: String
    public var display: SegmentDisplay

    public init(
        id: UUID = UUID(),
        vendor: Vendor,
        account: AccountSelection,
        metricName: String,
        display: SegmentDisplay
    ) {
        self.id = id
        self.vendor = vendor
        self.account = account
        self.metricName = metricName
        self.display = display
    }
}

// MARK: - Default letters

/// Maps known metric names to their canonical menu bar letter. When unknown,
/// the first character of the metric name (uppercased) is used as default.
public enum MenuBarMetricLetter {
    private static let knownAbbreviations: [String: String] = [
        "5h sessions (all models)": "S",
        "Weekly (all models)": "W",
    ]

    public static func defaultLetter(for metricName: String) -> String {
        if let known = knownAbbreviations[metricName] {
            return known
        }
        return String(metricName.prefix(1)).uppercased()
    }
}

import Foundation
import Observation

// MARK: - Clock abstraction (testable time source)

/// Abstracts `Date.now` so tests can inject a fixed point in time.
public protocol ClockProvider: Sendable {
    func now() -> Date
}

public struct SystemClock: ClockProvider {
    public init() {}
    public func now() -> Date { Date() }
}

// MARK: - Store

/// One segment of the menu bar label — a single metric's formatted text, its tier,
/// and whether the leading colored dot should be drawn. Pay-as-you-go segments
/// render without a dot; time-window segments respect the user's `showDot` toggle.
public struct MenuBarSegment: Sendable, Equatable {
    public let text: String
    public let tier: ConsumptionTier?
    public let showDot: Bool

    public init(text: String, tier: ConsumptionTier?, showDot: Bool) {
        self.text = text
        self.tier = tier
        self.showDot = showDot
    }
}

/// Formats the user-configured menu bar segments. Iterates the segments declared
/// in `AppPreferences.menuBarSegments`, resolves each against the latest usages
/// file contents, and exposes the rendered label text + per-segment payloads.
/// Falls back to `"--"` when no segment can be rendered.
@Observable
@MainActor
public final class UsageStore {
    public private(set) var menuBarText: String = "--"
    public private(set) var menuBarTier: ConsumptionTier?
    public private(set) var menuBarSegments: [MenuBarSegment] = []
    /// Incremented each time handleNewData is called, whether the data is valid or malformed.
    /// Tests use this as a reliable signal that the store has consumed the latest yielded item.
    public private(set) var dataProcessedCount: Int = 0
    public private(set) var entries: [VendorUsageEntry] = []
    public private(set) var outagesByVendor: [Vendor: [Outage]] = [:]

    // MARK: Dependencies

    private let fileWatcher: FileWatching
    private let clock: ClockProvider
    private let logger: FileLogger
    private let preferences: any AppPreferences
    private let countdownRefreshSeconds: UInt64

    public static let defaultCountdownRefreshSeconds: UInt64 = 60
    private static let fallbackText = "--"
    private static let rawPreviewMaxBytes = 200

    private static func rawPreview(_ data: Data) -> String {
        let slice = data.prefix(rawPreviewMaxBytes)
        if let text = String(data: slice, encoding: .utf8) {
            return "utf8:\(text.debugDescription)"
        }
        let hex = slice.map { String(format: "%02x", $0) }.joined()
        return "hex:\(hex)"
    }

    // Latest decoded file kept for countdown refresh without re-reading disk
    private var lastFile: UsagesFile?

    private var watchTask: Task<Void, Never>?
    private var countdownTask: Task<Void, Never>?

    public init(
        fileWatcher: FileWatching,
        clock: ClockProvider = SystemClock(),
        logger: FileLogger = Loggers.app,
        preferences: (any AppPreferences)? = nil,
        countdownRefreshSeconds: UInt64 = UsageStore.defaultCountdownRefreshSeconds
    ) {
        self.fileWatcher = fileWatcher
        self.clock = clock
        self.logger = logger
        // Default preferences mirror the pre-settings-window behaviour (S + W for
        // currently-active Claude account) so existing callers and tests that
        // don't supply a preferences store still get meaningful output.
        self.preferences = preferences ?? Self.makeDefaultPreferences()
        self.countdownRefreshSeconds = countdownRefreshSeconds
    }

    private static func makeDefaultPreferences() -> any AppPreferences {
        InMemoryAppPreferences(
            menuBarSegments: MenuBarSegmentsSeeder.defaultSegments(),
            menuBarSegmentsInitialized: true
        )
    }

    // MARK: Lifecycle

    /// Start watching the file and refreshing the countdown.
    /// Idempotent — calling again is a no-op.
    public func start() {
        guard watchTask == nil else { return }

        let watcher = fileWatcher
        // Self is captured strongly; stop() cancels both tasks to break the cycle
        watchTask = Task { [self] in
            for await data in watcher.changes() {
                guard !Task.isCancelled else { break }
                self.handleNewData(data)
            }
        }

        countdownTask = Task { [self] in
            let refreshNanos = self.countdownRefreshSeconds * 1_000_000_000
            while !Task.isCancelled {
                // CancellationError swallowed intentionally; checked on next loop iteration
                try? await Task.sleep(nanoseconds: refreshNanos)
                guard !Task.isCancelled else { break }
                self.refreshMenuBarText()
            }
        }

        trackPreferencesChanges()
    }

    /// Stop all background tasks. Idempotent.
    public func stop() {
        watchTask?.cancel()
        watchTask = nil
        countdownTask?.cancel()
        countdownTask = nil
    }

    // Defensive: cancels tasks when the store is released without an explicit stop() call.
    @MainActor deinit { stop() }

    // MARK: - Processing

    private func handleNewData(_ data: Data) {
        dataProcessedCount += 1
        do {
            let file = try JSONDecoder().decode(UsagesFile.self, from: data)
            lastFile = file
            entries = file.usages
            outagesByVendor = file.outagesByVendor
            applyFormat()
        } catch {
            let preview = Self.rawPreview(data)
            logger.log(.error, "UsageStore: JSON decode failed: \(error) — bytes=\(data.count), preview=\(preview)")
            lastFile = nil
            entries = []
            outagesByVendor = [:]
            menuBarText = Self.fallbackText
            menuBarTier = nil
            menuBarSegments = []
        }
    }

    private func refreshMenuBarText() {
        guard lastFile != nil else { return }
        applyFormat()
    }

    /// Re-runs formatting whenever `preferences.menuBarSegments` changes so the
    /// menu bar updates as the user edits the segment configuration. Tracking
    /// fires once per registration — re-arm inside the callback.
    private func trackPreferencesChanges() {
        withObservationTracking {
            _ = preferences.menuBarSegments
        } onChange: { [weak self] in
            Task { @MainActor in
                guard let self else { return }
                self.refreshMenuBarText()
                self.trackPreferencesChanges()
            }
        }
    }

    // MARK: - Formatting

    private func applyFormat() {
        let now = clock.now()
        let configs = preferences.menuBarSegments
        var rendered: [MenuBarSegment] = []
        for config in configs {
            let resolution = MenuBarSegmentResolver.resolve(config: config, entries: entries, now: now)
            if let segment = resolution.rendered {
                rendered.append(segment)
            } else if let issue = resolution.issue {
                logger.log(.debug, "UsageStore: skipping segment \(config.metricName) — \(issue)")
            }
        }
        menuBarSegments = rendered
        menuBarText = rendered.isEmpty ? Self.fallbackText : rendered.map(\.text).joined(separator: " | ")
        menuBarTier = rendered.compactMap(\.tier).max()
    }
}

import Foundation

// MARK: - Resolution

public enum MenuBarSegmentIssue: Equatable, Sendable {
    /// `.currentlyActive` was selected but no account for the vendor is flagged active.
    case noActiveAccount(vendor: Vendor)
    /// A specific account was selected but it's absent from the usages file.
    case accountNotFound(vendor: Vendor, email: AccountEmail)
    /// The target metric name is not present on the resolved account.
    case metricNotFound(metricName: String)
    /// The metric exists but its kind doesn't match the configured display variant
    /// (e.g. timeWindow display on a pay-as-you-go metric). Happens when the user
    /// changes the underlying metric kind externally.
    case metricKindMismatch
}

public struct ResolvedMenuBarSegment: Sendable {
    public let config: MenuBarSegmentConfig
    public let rendered: MenuBarSegment?
    public let issue: MenuBarSegmentIssue?

    public init(config: MenuBarSegmentConfig, rendered: MenuBarSegment?, issue: MenuBarSegmentIssue?) {
        self.config = config
        self.rendered = rendered
        self.issue = issue
    }
}

// MARK: - Resolver

/// Converts a `MenuBarSegmentConfig` + a snapshot of usage entries into either a
/// renderable `MenuBarSegment` or a structured issue that the Settings UI can
/// surface to the user.
public enum MenuBarSegmentResolver {

    public static func resolve(
        config: MenuBarSegmentConfig,
        entries: [VendorUsageEntry],
        now: Date
    ) -> ResolvedMenuBarSegment {
        let vendorEntries = entries.filter { $0.vendor == config.vendor }

        let entry: VendorUsageEntry?
        let resolveIssue: MenuBarSegmentIssue?
        switch config.account {
        case .currentlyActive:
            if let active = vendorEntries.first(where: { $0.isActive }) {
                entry = active
                resolveIssue = nil
            } else if vendorEntries.count == 1 {
                // No account is flagged active, but there is only one — treat it as implicitly active
                // so the user sees their data without having to wait for the monitor to sync.
                entry = vendorEntries[0]
                resolveIssue = nil
            } else {
                entry = nil
                resolveIssue = .noActiveAccount(vendor: config.vendor)
            }
        case .specific(let email):
            if let match = vendorEntries.first(where: { $0.account == email }) {
                entry = match
                resolveIssue = nil
            } else {
                entry = nil
                resolveIssue = .accountNotFound(vendor: config.vendor, email: email)
            }
        }

        guard let entry else {
            return ResolvedMenuBarSegment(config: config, rendered: nil, issue: resolveIssue)
        }

        guard let metric = entry.metrics.first(where: { metricName($0) == config.metricName }) else {
            return ResolvedMenuBarSegment(
                config: config,
                rendered: nil,
                issue: .metricNotFound(metricName: config.metricName)
            )
        }

        switch (metric, config.display) {
        case let (.timeWindow(_, resetAt, windowDuration, usagePercent), .timeWindow(display)):
            let segment = renderTimeWindow(
                display: display,
                resetAt: resetAt,
                windowDuration: windowDuration,
                usagePercent: usagePercent,
                now: now
            )
            return ResolvedMenuBarSegment(config: config, rendered: segment, issue: nil)

        case let (.payAsYouGo(_, currentAmount, currency), .payAsYouGo):
            let segment = renderPayAsYouGo(currentAmount: currentAmount, currency: currency)
            return ResolvedMenuBarSegment(config: config, rendered: segment, issue: nil)

        default:
            return ResolvedMenuBarSegment(config: config, rendered: nil, issue: .metricKindMismatch)
        }
    }

    private static func metricName(_ metric: UsageMetric) -> String? {
        switch metric {
        case .timeWindow(let name, _, _, _):   return name
        case .payAsYouGo(let name, _, _):      return name
        case .unknown:                         return nil
        }
    }

    // MARK: Rendering

    private static func renderTimeWindow(
        display: TimeWindowDisplay,
        resetAt: ISODate?,
        windowDuration: DurationMinutes,
        usagePercent: UsagePercent,
        now: Date
    ) -> MenuBarSegment? {
        var parts: [String] = []
        if display.showLetter, !display.letter.isEmpty {
            parts.append(display.letter)
        }
        if display.showPercent {
            parts.append("\(usagePercent.rawValue)%")
        }
        if display.showReset {
            let remaining = resetAt.map { formatRemainingTime(resetAt: $0, now: now) } ?? "???"
            parts.append(remaining)
        }
        let text = parts.joined(separator: " ")

        let tier: ConsumptionTier?
        if display.showDot {
            let theoretical = resetAt.map { theoreticalFraction(resetAt: $0, windowDuration: windowDuration, now: now) } ?? 0.0
            tier = consumptionRatio(actualPercent: usagePercent, theoreticalFraction: theoretical)
                .map { consumptionTier(ratio: $0) }
        } else {
            tier = nil
        }

        // If the user turned every visible element off, there's nothing to render
        if text.isEmpty, !display.showDot {
            return nil
        }

        return MenuBarSegment(text: text, tier: tier, showDot: display.showDot)
    }

    private static func renderPayAsYouGo(currentAmount: Double, currency: String) -> MenuBarSegment {
        let amount = String(format: "%.2f", currentAmount)
        return MenuBarSegment(text: "\(amount) \(currency)", tier: nil, showDot: false)
    }
}

import AppKit
import AIUsagesTrackersLib

/// Rasterises the full menu bar label into a non-template `NSImage`.
/// MenuBarExtra's label was unusable: template tinting stripped the per-tier
/// dot colors, and mixed HStacks silently truncated segments past the first.
/// With a custom `NSStatusItem`, we control `isTemplate = false` so hues
/// survive and we pick the text color from the status button's effective
/// appearance (which tracks the menu bar, not the app).
@MainActor
enum MenuBarLabelRenderer {
    private static let font: NSFont = .menuBarFont(ofSize: 0)
    private static let separator = " | "
    private static let dot = "● "
    private static let horizontalPadding: CGFloat = 4
    private static let height: CGFloat = 18

    static func render(
        segments: [MenuBarSegment],
        fallbackText: String,
        isDarkMenuBar: Bool
    ) -> NSImage {
        let textColor: NSColor = isDarkMenuBar ? .white : .black
        let attributed = attributedString(
            segments: segments,
            fallbackText: fallbackText,
            textColor: textColor
        )
        let textSize = attributed.size()
        let width = ceil(textSize.width) + horizontalPadding * 2
        let size = NSSize(width: max(width, 1), height: height)
        let image = NSImage(size: size)
        image.lockFocus()
        let textY = (height - ceil(textSize.height)) / 2
        attributed.draw(at: NSPoint(x: horizontalPadding, y: textY))
        image.unlockFocus()
        image.isTemplate = false
        return image
    }

    private static func attributedString(
        segments: [MenuBarSegment],
        fallbackText: String,
        textColor: NSColor
    ) -> NSAttributedString {
        guard !segments.isEmpty else {
            return NSAttributedString(
                string: fallbackText,
                attributes: [.font: font, .foregroundColor: textColor]
            )
        }
        let result = NSMutableAttributedString()
        for (index, segment) in segments.enumerated() {
            if index > 0 {
                result.append(NSAttributedString(
                    string: separator,
                    attributes: [.font: font, .foregroundColor: textColor]
                ))
            }
            if segment.showDot {
                let dotColor = segment.tier?.nsColor ?? textColor
                result.append(NSAttributedString(
                    string: dot,
                    attributes: [.font: font, .foregroundColor: dotColor]
                ))
            }
            result.append(NSAttributedString(
                string: segment.text,
                attributes: [.font: font, .foregroundColor: textColor]
            ))
        }
        return result
    }
}

