import SwiftUI
import AppKit
import AIUsagesTrackersLib

enum VendorBranding {
    struct Brand: Equatable, Sendable {
        let assetName: String
        let displayName: String
        let tintHex: String
    }

    static func brand(for vendor: Vendor) -> Brand? {
        switch vendor {
        case .claude:
            Brand(
                assetName: "claude-mark",
                displayName: "Claude Code",
                tintHex: "DA7756"
            )
        case .codex:
            Brand(
                assetName: "codex-mark",
                displayName: "Codex",
                tintHex: "10A37F"
            )
        default:
            nil
        }
    }

    static func displayName(for vendor: Vendor) -> String {
        brand(for: vendor)?.displayName ?? vendor.rawValue
    }

    static func tint(for vendor: Vendor) -> Color? {
        guard let tintHex = brand(for: vendor)?.tintHex else { return nil }
        return Color(hex: tintHex)
    }

    static func icon(for vendor: Vendor) -> NSImage? {
        guard let assetName = brand(for: vendor)?.assetName else { return nil }
        return loadTemplateImage(named: assetName)
    }

    private static func loadTemplateImage(named assetName: String) -> NSImage? {
        guard let url = Bundle.module.url(
            forResource: assetName,
            withExtension: "pdf",
            subdirectory: "VendorBranding"
        ), let image = NSImage(contentsOf: url) else {
            return nil
        }

        image.isTemplate = true
        return image
    }
}

struct VendorIconView: View {
    let vendor: Vendor
    var size: CGFloat = 14

    var body: some View {
        if let image = VendorBranding.icon(for: vendor),
           let tint = VendorBranding.tint(for: vendor) {
            Image(nsImage: image)
                .renderingMode(.template)
                .resizable()
                .scaledToFit()
                .frame(width: size, height: size)
                .foregroundStyle(tint)
                .accessibilityHidden(true)
        }
    }
}

struct VendorLabelView: View {
    let vendor: Vendor
    var iconSize: CGFloat = 14

    var body: some View {
        HStack(spacing: 6) {
            VendorIconView(vendor: vendor, size: iconSize)
            Text(VendorBranding.displayName(for: vendor))
        }
    }
}

private extension Color {
    init?(hex: String) {
        guard hex.count == 6, let value = Int(hex, radix: 16) else { return nil }

        let red = Double((value >> 16) & 0xFF) / 255.0
        let green = Double((value >> 8) & 0xFF) / 255.0
        let blue = Double(value & 0xFF) / 255.0

        self.init(red: red, green: green, blue: blue)
    }
}

import Foundation
import Testing
@testable import AIUsagesTrackersLib

@Suite("AccountSelection")
struct AccountSelectionTests {
    @Test("currentlyActive round-trips through Codable")
    func currentlyActiveRoundTrip() throws {
        let original = AccountSelection.currentlyActive
        let data = try JSONEncoder().encode(original)
        let decoded = try JSONDecoder().decode(AccountSelection.self, from: data)
        #expect(decoded == original)
    }

    @Test("specific round-trips through Codable")
    func specificRoundTrip() throws {
        let original = AccountSelection.specific("user@example.com")
        let data = try JSONEncoder().encode(original)
        let decoded = try JSONDecoder().decode(AccountSelection.self, from: data)
        #expect(decoded == original)
    }

    @Test("currentlyActive encodes with stable discriminator")
    func currentlyActiveStableEncoding() throws {
        let data = try JSONEncoder().encode(AccountSelection.currentlyActive)
        let json = String(data: data, encoding: .utf8) ?? ""
        #expect(json.contains("\"currently-active\""))
    }

    @Test("specific encodes with email field")
    func specificEncoding() throws {
        let data = try JSONEncoder().encode(AccountSelection.specific("alice@example.com"))
        let json = String(data: data, encoding: .utf8) ?? ""
        #expect(json.contains("alice@example.com"))
        #expect(json.contains("\"specific\""))
    }
}

@Suite("SegmentDisplay")
struct SegmentDisplayTests {
    @Test("timeWindow round-trips preserving all flags")
    func timeWindowRoundTrip() throws {
        let original = SegmentDisplay.timeWindow(TimeWindowDisplay(
            showDot: false,
            showLetter: true,
            letter: "X",
            showPercent: false,
            showReset: true
        ))
        let data = try JSONEncoder().encode(original)
        let decoded = try JSONDecoder().decode(SegmentDisplay.self, from: data)
        #expect(decoded == original)
    }

    @Test("payAsYouGo round-trips without extra fields")
    func payAsYouGoRoundTrip() throws {
        let original = SegmentDisplay.payAsYouGo
        let data = try JSONEncoder().encode(original)
        let decoded = try JSONDecoder().decode(SegmentDisplay.self, from: data)
        #expect(decoded == original)
    }

    @Test("TimeWindowDisplay default init enables all toggles")
    func timeWindowDefaults() {
        let display = TimeWindowDisplay()
        #expect(display.showDot)
        #expect(display.showLetter)
        #expect(display.showPercent)
        #expect(display.showReset)
    }
}

@Suite("MenuBarSegmentConfig")
struct MenuBarSegmentConfigTests {
    @Test("round-trips through Codable")
    func roundTrip() throws {
        let original = MenuBarSegmentConfig(
            vendor: .claude,
            account: .currentlyActive,
            metricName: "Weekly (all models)",
            display: .timeWindow(TimeWindowDisplay(letter: "W"))
        )
        let data = try JSONEncoder().encode(original)
        let decoded = try JSONDecoder().decode(MenuBarSegmentConfig.self, from: data)
        #expect(decoded == original)
    }

    @Test("id survives Codable round-trip")
    func idSurvivesRoundTrip() throws {
        let original = MenuBarSegmentConfig(
            vendor: .claude,
            account: .specific("a@b.com"),
            metricName: "Weekly (all models)",
            display: .payAsYouGo
        )
        let data = try JSONEncoder().encode(original)
        let decoded = try JSONDecoder().decode(MenuBarSegmentConfig.self, from: data)
        #expect(decoded.id == original.id)
    }

    @Test("array of mixed segments round-trips")
    func arrayRoundTrip() throws {
        let segments: [MenuBarSegmentConfig] = [
            MenuBarSegmentConfig(
                vendor: .claude,
                account: .currentlyActive,
                metricName: "5h sessions (all models)",
                display: .timeWindow(TimeWindowDisplay(letter: "S"))
            ),
            MenuBarSegmentConfig(
                vendor: .claude,
                account: .specific("user@example.com"),
                metricName: "Monthly cost",
                display: .payAsYouGo
            ),
        ]
        let data = try JSONEncoder().encode(segments)
        let decoded = try JSONDecoder().decode([MenuBarSegmentConfig].self, from: data)
        #expect(decoded == segments)
    }
}

@Suite("MenuBarMetricLetter")
struct MenuBarMetricLetterTests {
    @Test("known 5h sessions maps to S")
    func fiveHourSessions() {
        #expect(MenuBarMetricLetter.defaultLetter(for: "5h sessions (all models)") == "S")
    }

    @Test("known Weekly maps to W")
    func weekly() {
        #expect(MenuBarMetricLetter.defaultLetter(for: "Weekly (all models)") == "W")
    }

    @Test("unknown metric falls back to first char uppercased")
    func unknownFallback() {
        #expect(MenuBarMetricLetter.defaultLetter(for: "opus 4.7") == "O")
    }

    @Test("empty name yields empty letter")
    func empty() {
        #expect(MenuBarMetricLetter.defaultLetter(for: "") == "")
    }
}

import Foundation
import Testing
@testable import AIUsagesTrackersLib

private let referenceDate: Date = ISO8601DateFormatter().date(from: "2026-04-17T12:47:00Z")!

private func timeWindowEntry(
    vendor: Vendor = .claude,
    account: AccountEmail = "user@example.com",
    isActive: Bool = true,
    metricName: String = "5h sessions (all models)",
    resetAt: String = "2026-04-17T15:00:00Z",
    usagePercent: Int = 48
) -> VendorUsageEntry {
    VendorUsageEntry(
        vendor: vendor,
        account: account,
        isActive: isActive,
        metrics: [.timeWindow(
            name: metricName,
            resetAt: ISODate(rawValue: resetAt),
            windowDuration: 300,
            usagePercent: UsagePercent(rawValue: usagePercent)
        )]
    )
}

private func payAsYouGoEntry(
    account: AccountEmail = "user@example.com",
    metricName: String = "Monthly cost",
    amount: Double = 12.50,
    currency: String = "USD"
) -> VendorUsageEntry {
    VendorUsageEntry(
        vendor: .claude,
        account: account,
        isActive: true,
        metrics: [.payAsYouGo(name: metricName, currentAmount: amount, currency: currency)]
    )
}

@Suite("MenuBarSegmentResolver — .currentlyActive")
struct ResolverCurrentlyActiveTests {
    @Test("renders when an active account exists")
    func rendersWhenActive() {
        let config = MenuBarSegmentConfig(
            vendor: .claude,
            account: .currentlyActive,
            metricName: "5h sessions (all models)",
            display: .timeWindow(TimeWindowDisplay(letter: "S"))
        )
        let result = MenuBarSegmentResolver.resolve(
            config: config,
            entries: [timeWindowEntry()],
            now: referenceDate
        )
        #expect(result.issue == nil)
        #expect(result.rendered?.text == "S 48% 2h 13m")
        #expect(result.rendered?.showDot == true)
    }

